Rules.InvariantScript:
If(
    locFormMode="New",
    // TRUE CASE
    UpdateContext({locCurrentRoomProperty: "Room"});
    ClearCollect(
        colRoomProperties,
        {
            Value: "",
            Attribute: "Room"
        }
    ),
    // ELSE CASE
    UpdateContext({locCurrentRoomProperty: "Description"});
    ClearCollect(
        colRoomProperties,
        {
            Value: gblRecordJobEntryCurrent_.'Room: Type',
            ID: GUID(),
            Attribute: "Room"
        },
        {
            Value: gblRecordJobEntryCurrent_.'Room: Floor',
            ID: GUID(),
            Attribute: "Floor"
        },
        {
            Value: gblRecordJobEntryCurrent_.'Room: Description',
            ID: GUID(),
            Attribute: "Description"
        }
    );
    
)

// clear collections
ClearCollect(
    locRoomProperties,
    {
        Value: "",
        Attribute: "Room"
    }
);
UpdateContext({locPreviousScreen: ""});
// reset controls
Reset(gal_AddRoom_Selection);
Reset(lbl_AddRoom_Description);

Switch(
    gal_AddRoom_Selected.Selected.Attribute,
    "Room",
    RenameColumns(
        ShowColumns(
            Filter(
                colCdsDataEntryChoices,
                Type = gblOptionSets.Global.DataEntryType.Room
            ),
            'Data Entry Choice',
            Value
        ),
        wn_dataentrychoiceid,
        ID,
        wn_value,
        Value
    ),
    "Floor",
    Table(
        {
            Value: "Basement",
            ID: "0"
        },
        {
            Value: "1st Floor",
            ID: "1"
        },
        {
            Value: "2nd Floor",
            ID: "2"
        },
        {
            Value: "3rd Floor",
            ID: "3"
        },
        {
            Value: "4th Floor",
            ID: "4"
        },
        {
            Value: "5th Floor",
            ID: "5"
        }
    ),
    "Description",
    Blank(),
    "Window",
    RenameColumns(
        ShowColumns(
            AddColumns(
                Filter(
                    colCdsJobEntries,
                    Job.Job = gblRecordJobCurrent.Job,
                    Status <> gblOptionSets.JobEntry.Status.Inactive
                ),
                Value,
                Concatenate(
                    First(
                        ForAll(Split(
                            Name,
                            " > "
                        ), {Result: ThisRecord.Value})
                    ).Result,
                    Char(13),
                    'Room: Type',
                    Char(13),
                    'Room: Floor'
                )
            ),
            'Job Entry',
            Value
        ),
        hsl_jobentryid,
        ID
    )
)

// add the next window attribute to window properties
If(
    LookUp(
        colRoomProperties,
        Attribute = locCurrentRoomProperty,
        Value
    ) = "",
    Switch(
        locCurrentRoomProperty,
        "Room",
        Collect(
            colRoomProperties,
            {
                Attribute: "Floor",
                ID: "",
                Value: ""
            }
        ),
        "Floor",
        Collect(
            colRoomProperties,
            {
                Attribute: "Description",
                ID: "",
                Value: ""
            }
        ),
        "Description",
        Collect(
            colRoomProperties,
            {
                Attribute: "Window",
                ID: "",
                Value: ""
            }
        ),
        "Window",
        Set(
            gblRecordJobEntryCurrent_,
            LookUp(
                colCdsJobEntries,
                'Job Entry'=GUID(ThisItem.ID)
            )
        )
    )
);
// change to the next window property
UpdateContext({
    locCurrentRoomProperty:
    Switch(
        locCurrentRoomProperty,
        "Room",
        "Floor",
        "Floor",
        "Description",
        "Description",
        "Window",
        "Window"
    )
});
// write the selection to the window property
Patch(
    colRoomProperties,
    LookUp(
        colRoomProperties,
        Attribute = gal_AddRoom_Selected.Selected.Attribute
    ),
    {
        ID: ThisItem.ID,
        Value: Substitute(ThisItem.Value, Char(13), ", ")
    }
);
Reset(gal_AddRoom_Selected);
Reset(gal_AddRoom_Selection);

Collect(
    colRoomProperties,
    {
        Attribute: "Window",
        ID: "",
        Value: ""
    }
);
// change to the next window property
UpdateContext({locCurrentRoomProperty: "Window"});
Reset(gal_AddRoom_Selected);
Reset(gal_AddRoom_Selection);

// store the job entry GUID to be cloned
UpdateContext({locCloneJobEntryGUID: gblRecordJobEntryCurrent_.'Job Entry'});
If(
    locFormMode = "New",
// create new job entry record
    With(
        {
            varType: "colCdsJobEntries",
            varRecordRef: GUID()
        },
        Set(
            gblRecordJobEntryCurrent_,
            Patch(
                colCdsJobEntries,
                Defaults(colCdsJobEntries),
                //gblRecordJobEntryCurrent_,
                {
                    Completed: gblOptionSets.JobEntry.Completed.No,
                    'Job Entry': varRecordRef,
                    Job: LookUp(
                        colCdsJobs,
                        Job = gblRecordJobCurrent.Job
                    ),
                    'Job Stage': gblRecordJobEntryCurrent_.'Job Stage',
                    'Job Entry Option (Header)': gblRecordJobEntryCurrent_.'Job Entry Option (Header)',
                    'Measurement (Sales)': Blank(),
                    Name: gblRecordJobEntryCurrent_.Name,

                    'Room: Description': lbl_AddRoom_Description.Text,
                    'Room: Floor': LookUp(
                        colRoomProperties,
                        Attribute = "Floor",
                        Value
                    ),
                    'Room: Type': LookUp(
                        colRoomProperties,
                        Attribute = "Room",
                        Value
                    ),
                    'Sequence Number': gblRecordJobEntryCurrent_.'Sequence Number',
                    'Window Choice': gblRecordJobEntryCurrent_.'Window Choice',
                    appJobRoomIdText: gblRecordJobEntryCurrent_.appJobRoomIdText,
                    appJobIdText: gblRecordJobEntryCurrent_.appJobIdText
                }
            )
        );
        Collect(
            colAUDRecords,
            {
                Type: "colCdsJobEntries",
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        );
        // add new job entries and job entry selections
ForAll(
            Filter(
                colCdsJobEntrySelections,
                'Job Entry'.'Job Entry' = locCloneJobEntryGUID
            ) As tblJobEntrySelections,
            With(
                {
                    varType: "colCdsJobEntrySelections",
                    varRecordRef: GUID()
                },
                Patch(
                    colCdsJobEntrySelections,
                    Defaults(colCdsJobEntrySelections),
                    {
                        'Job Entry Selection': varRecordRef,
                        'Job Entry': gblRecordJobEntryCurrent_,
                        'Job Entry Option (Attribute)': tblJobEntrySelections[@'Job Entry Option (Attribute)'],
                        'Job Entry Option (Value)': tblJobEntrySelections[@'Job Entry Option (Value)'],
                        'Job Entry Option (Value) (Sales)': tblJobEntrySelections[@'Job Entry Option (Value) (Sales)']
                    }
                );
                Collect(
                    colAUDRecords,
                    {
                        Type: varType,
                        RecordRef: varRecordRef,
                        Job: gblRecordJobCurrent.Job,
                        Operation: "A"
                    }
                )
            )
        )
    );
    ForAll(
        Sequence(1),
        With(
            {
                varType: "colCdsWindowMeasurements",
                varRecordRef: GUID()
            },
            Patch(
                colCdsWindowMeasurements,
                Defaults(colCdsWindowMeasurements),
                {
                    Name: "Tech 0"" x 0""",
                    'Exception?': gblOptionSets.WindowMeasurement.Exception.No,
                    Height: 0,
                    Job: gblRecordJobCurrent,
                    'Job Entry': gblRecordJobEntryCurrent_,
                    Type: gblOptionSets.WindowMeasurement.Type.Tech,
                    Width: 0,
                    'Window Measurement': varRecordRef
                }
            );
            Collect(
                colAUDRecords,
                {
                    Type: varType,
                    RecordRef: varRecordRef,
                    Job: gblRecordJobCurrent.Job,
                    Operation: "A"
                }
            )
        )
    );

// create project sidebar
ClearCollect(
        colProjectSidebar,
        Ungroup(
            Table(
                {
                    varMenuItems: RenameColumns(
                        Table(
                            {
                                ID: gblRecordJobEntryCurrent_.'Job Entry',
                                Name: Index(
                                    ForAll(
                                        Split(
                                            gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                            " > "
                                        ),
                                        {Result: ThisRecord.Value}
                                    ),
                                    2
                                ).Result,
                                Category: "Job Entry",
                                Description: Index(
                                    ForAll(
                                        Split(
                                            gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                            " > "
                                        ),
                                        {Result: ThisRecord.Value}
                                    ),
                                    1
                                ).Result,
                                Screen: 'Windows Screen',
                                Type: "Window Choice",
                                Image: 'dblhungw-2',
                                ImageDisabled: 'dblhungw-2'
                            }
                        ),
                        Name,
                        Title
                    )
                },
                {
                    varMenuItems: ShowColumns(
                        RenameColumns(
                            AddColumns(
                                Filter(
                                    colCdsWindowMeasurements,
                                    'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry',
                                    Type = gblOptionSets.WindowMeasurement.Type.Tech,
                                    Status <> gblOptionSets.WindowMeasurement.Status.Inactive
                                ),
                                Category,
                                "Window Measurement",
                                Description,
                                If(
                                    'United Inches (UI)' = 0,
                                    "Sales Measurement",
                                    "Tech Measurement"
                                ),
                                Image,
                                gblAppIcons.Ruler,
                                ImageDisabled,
                                gblAppIcons.RulerDisabled,
                                Screen,
                                'Measure Window Screen',
                                Title,
                                If(
                                    'United Inches (UI)' = 0,
                                    $"{Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Width)}"" x {Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Height)}""",
                                    $"{RoundDown(
                                        Width,
                                        0
                                    )} {Switch(
                                        Mod(
                                            Width,
                                            1
                                        ),
                                        0,
                                        "",
                                        0.125,
                                        "1/8",
                                        0.250,
                                        "1/4",
                                        0.375,
                                        "3/8",
                                        0.500,
                                        "1/2",
                                        0.625,
                                        "5/8",
                                        0.750,
                                        "3/4",
                                        0.875,
                                        "7/8"
                                    )}"" x {RoundDown(
                                        Height,
                                        0
                                    )} {Switch(
                                        Mod(
                                            Height,
                                            1
                                        ),
                                        0,
                                        "",
                                        0.125,
                                        "1/8",
                                        0.250,
                                        "1/4",
                                        0.375,
                                        "3/8",
                                        0.500,
                                        "1/2",
                                        0.625,
                                        "5/8",
                                        0.750,
                                        "3/4",
                                        0.875,
                                        "7/8"
                                    )}"""
                                )
                            ),
                            'Window Measurement',
                            ID
                        ),
                        ID,
                        Title,
                        Category,
                        Description,
                        Screen,
                        Image,
                        ImageDisabled
                    )
                }
            ),
            varMenuItems
        )
    );
    Set(
        gblProjectSidebarItemCurrent,
        First(colProjectSidebar)
    ),
    locFormMode = "Edit",
    With(
        {
            varType: "colCdsJobEntries",
            varRecordRef: gblRecordJobEntryCurrent_.'Job Entry'
        },
        Set(
            gblRecordJobEntryCurrent_,
            Patch(
                colCdsJobEntries,
                gblRecordJobEntryCurrent_,
                {
                    'Room: Description': lbl_AddRoom_Description.Text,
                    'Room: Floor': LookUp(
                        colRoomProperties,
                        Attribute = "Floor",
                        Value
                    ),
                    'Room: Type': LookUp(
                        colRoomProperties,
                        Attribute = "Room",
                        Value
                    )
                }
            )
        );
        If(
            IsBlank(
                LookUp(
                    colAUDRecords,
                    Type = varType
                    And RecordRef = varRecordRef
                )
            ),
            Collect(
                colAUDRecords,
                {
                    Type: "colCdsJobEntries",
                    RecordRef: varRecordRef,
                    Job: gblRecordJobCurrent.Job,
                    Operation: "U"
                }
            )
        )
    )
);
//save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobEntries,
        "localCdsJobEntries"
    );
    SaveData(
        colCdsJobEntrySelections,
        "localCdsJobEntrySelections"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
);
// leave the screen and reset
Reset(gal_AddRoom_Selection);
Reset(gal_AddRoom_Selected);
// next screen
If(
    And(
        locFormMode = "Edit",
        locPreviousScreen = "Rooms Screen"
    ),
    Navigate(
        'Rooms Screen',
        ScreenTransition.None
    ),
    Navigate(
        'Windows Screen',
        ScreenTransition.None
    )
);
